// src/server.ts
function createServer(workspaceRoot) {
  const server = new McpServer({
    name: "cursor-bridge",
    version: "0.1.0"
  });
  async function rebuildIndex() {
    const config2 = await loadConfig(workspaceRoot);
    return buildIndex(workspaceRoot, config2);
  }
  server.tool(
    "get_active_rules",
    "Returns rules that apply to a given set of files and/or task description. Call at session start or when switching file context.",
    {
      files: external_exports.array(external_exports.string()).optional().describe("File paths relative to workspace root"),
      task_description: external_exports.string().optional().describe("Description of the current task for agent-requested rule matching")
    },
    async ({ files, task_description }) => {
      if (!files?.length && !task_description) {
        return {
          content: [{ type: "text", text: JSON.stringify({ error: "At least one of 'files' or 'task_description' must be provided" }) }],
          isError: true
        };
      }
      const index = await rebuildIndex();
      const result = await getActiveRules(index, files, task_description);
      return { content: [{ type: "text", text: JSON.stringify(result, null, 2) }] };
    }
  );
  server.tool(
    "get_context_index",
    "Returns a lightweight menu of all available context \u2014 rules, agents, and skills \u2014 with descriptions only, no content.",
    {
      types: external_exports.array(external_exports.enum(["rule", "agent", "skill"])).optional().describe("Which context types to include. Defaults to all three.")
    },
    async ({ types: types2 }) => {
      const index = await rebuildIndex();
      const requestedTypes = types2 ?? ["rule", "agent", "skill"];
      const result = {};
      if (requestedTypes.includes("rule")) {
        result.rules = Array.from(index.rules.values()).map((r) => ({
          name: r.name,
          description: r.description,
          mode: r.mode,
          globs: r.globs
        }));
      }
      if (requestedTypes.includes("agent")) {
        result.agents = Array.from(index.agents.values()).map((a) => ({
          name: a.name,
          description: a.description,
          model: a.model,
          readonly: a.readonly,
          is_background: a.isBackground
        }));
      }
      if (requestedTypes.includes("skill")) {
        result.skills = Array.from(index.skills.values()).map((s) => ({
          name: s.name,
          description: s.description,
          has_scripts: s.supportingFiles.some((f) => f.startsWith("scripts/")),
          has_references: s.supportingFiles.some((f) => f.startsWith("references/"))
        }));
      }
      return { content: [{ type: "text", text: JSON.stringify(result, null, 2) }] };
    }
  );
  server.tool(
    "get_rule",
    "Fetches the full content of a specific rule by name.",
    {
      name: external_exports.string().describe("Rule name (as shown in get_context_index)")
    },
    async ({ name }) => {
      const index = await rebuildIndex();
      const rule = index.rules.get(name);
      if (!rule) {
        const available = Array.from(index.rules.keys()).join(", ");
        return {
          content: [{ type: "text", text: JSON.stringify({ error: `Rule '${name}' not found. Available rules: ${available}` }) }],
          isError: true
        };
      }
      const { content } = await parseFullFile(rule.filePath);
      return {
        content: [{
          type: "text",
          text: JSON.stringify({ name: rule.name, description: rule.description, content }, null, 2)
        }]
      };
    }
  );
  server.tool(
    "get_agent",
    "Fetches the full definition of a Cursor agent by name.",
    {
      name: external_exports.string().describe("Agent name (as shown in get_context_index)")
    },
    async ({ name }) => {
      const index = await rebuildIndex();
      const agent = index.agents.get(name);
      if (!agent) {
        const available = Array.from(index.agents.keys()).join(", ");
        return {
          content: [{ type: "text", text: JSON.stringify({ error: `Agent '${name}' not found. Available agents: ${available}` }) }],
          isError: true
        };
      }
      const { content } = await parseFullFile(agent.filePath);
      return {
        content: [{
          type: "text",
          text: JSON.stringify({
            name: agent.name,
            description: agent.description,
            model: agent.model,
            readonly: agent.readonly,
            is_background: agent.isBackground,
            instructions: content
          }, null, 2)
        }]
      };
    }
  );
  server.tool(
    "get_skill",
    "Fetches the full content of a skill package.",
    {
      name: external_exports.string().describe("Skill name (as shown in get_context_index)"),
      include_supporting_files: external_exports.boolean().optional().default(false).describe("If true, include supporting file paths")
    },
    async ({ name, include_supporting_files }) => {
      const index = await rebuildIndex();
      const skill = index.skills.get(name);
      if (!skill) {
        const available = Array.from(index.skills.keys()).join(", ");
        return {
          content: [{ type: "text", text: JSON.stringify({ error: `Skill '${name}' not found. Available skills: ${available}` }) }],
          isError: true
        };
      }
      const { content } = await parseFullFile(skill.filePath);
      const result = {
        name: skill.name,
        description: skill.description,
        metadata: skill.metadata,
        instructions: content
      };
      if (include_supporting_files) {
        result.supporting_files = skill.supportingFiles;
      }
      return { content: [{ type: "text", text: JSON.stringify(result, null, 2) }] };
    }
  );
  server.tool(
    "get_skill_file",
    "Fetches a specific supporting file from within a skill directory.",
    {
      skill_name: external_exports.string().describe("Name of the parent skill"),
      file_path: external_exports.string().describe("Relative path within the skill directory (e.g., 'scripts/extract-text.py')")
    },
    async ({ skill_name, file_path }) => {
      const index = await rebuildIndex();
      const skill = index.skills.get(skill_name);
      if (!skill) {
        return {
          content: [{ type: "text", text: JSON.stringify({ error: `Skill '${skill_name}' not found.` }) }],
          isError: true
        };
      }
      const path7 = await import("path");
      const resolved = path7.resolve(skill.directoryPath, file_path);
      if (!resolved.startsWith(skill.directoryPath)) {
        return {
          content: [{ type: "text", text: JSON.stringify({ error: "Invalid file path: must be within the skill directory" }) }],
          isError: true
        };
      }
      const normalizedFilePath = file_path.replace(/\\/g, "/");
      if (!skill.supportingFiles.includes(normalizedFilePath)) {
        const available = skill.supportingFiles.join(", ");
        return {
          content: [{ type: "text", text: JSON.stringify({ error: `File '${file_path}' not found in skill '${skill_name}'. Available files: ${available}` }) }],
          isError: true
        };
      }
      const fs = await import("fs/promises");
      try {
        const fileContent = await fs.readFile(resolved, "utf-8");
        return {
          content: [{
            type: "text",
            text: JSON.stringify({ skill_name, file_path: normalizedFilePath, content: fileContent }, null, 2)
          }]
        };
      } catch {
        const available = skill.supportingFiles.join(", ");
        return {
          content: [{ type: "text", text: JSON.stringify({ error: `File '${file_path}' not found in skill '${skill_name}'. Available files: ${available}` }) }],
          isError: true
        };
      }
    }
  );
  return server;
}

// src/index.ts
async function main() {
  const workspaceRoot = process.cwd();
  const server = createServer(workspaceRoot);
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("Cursor Bridge MCP server started");
}
main().catch((error48) => {
  console.error("Fatal error:", error48);
  process.exit(1);
});
